	.SBTTL	ICOMAINLOOP:	CLR.B	(A6)+OBUEXE	; ligne de commande vide	COMP.W	(A6)+OHISTI,#-1	; histoire en cours ?	JUMP',EQ 20$		; non => 20$				; oui => retourne au premier niveau	LOAD.W	(A6)+OLSTII,(A6)+OHISTI	TCLR.B	(A6)+OFLAGS:#BAFMIN	TCLR.B	(A6)+OFLAGS:#BLIST	TCLR.B	(A6)+OFLAGS:#BTEXT	TCLR.B	(A6)+OFLAGS:#BICONE	CLR.B	D3		; D3 <-- liste ncessaire	CALL	FRAPPE		; frappe l'icone de base	LOAD.W	(A6)+OHISTL,#1	; premier niveau	JUMP	LOOP220$:	CLR.W	(A6)+OHISTL	; niveau zro	CALL	AFICONE		; affiche tous les icones	LOAD.W	D4,(A6)+OMEMII	CALL	INVERSE		; montre le premier icone	LOAD.W	(A6)+OLSTII,D4	CALL	CLRFIFO		; vide le fifo du clavier !	CLR.L	(A6)+OPMENU	; faudra refaire soft-keysLOOP1:	CLR.B	(A6)+OBUEXE	; vide buffer de commandeLOOP2:	CALL	AFCOMM		; affiche la ligne de commande	CALL	AFMENU		; affiche le bon menuLOOPM:	TEST.B	(A6)+OFLAGM:#BMACRO ; macro en excution ?	JUMP',BC LOOP3		; non => LOOP3				; oui =>	CALL	GETMACRO	; lit une ligne de la macro	JUMP,EQ	EXECUTE	COMP.W	D7,#EROUTF	; fin de la macro ?	JUMP,EQ	LOOP		; oui => LOOP	LOAD.B	D3,#BIPERR	; non =>	LIB	?BEEP		; fait un vilain bruit	JUMP	LOOPLOOP3:	LOAD.W	D4,#50*60*5	; D4 <-- cinq minutes	NTREL	?SETTIM	LIB	?GETKEY		; attend touche/souris ...	PUSH.W	D7	LOAD.W	D4,#-1	NTREL	?SETTIM	POP.W	D7	JUMP',EQ 05$		; touche presse => 05$				; systme inactif =>	CLR.L	(A6)+OPMENU	LOAD.L	A3,#R16"TXMENN	LIB	?AFMENU		; annule toutes les soft-keys	CALL	AFSLEEP		; passe en demi-intensit !	LIB	?GETKEY		; attend qq chose ...	CALL	AFNOSLEEP	; remet deuzoutroi trucs	JUMP	LOOP05$:	TEST.L	D3:#BKPSEUDO	; touche relache/pseudo code ?	JUMP,BS	LOOP3		; oui => ignore	CALL	FILTRE		; filtre touche souris	LOAD.W	D2,D3		; D2 <-- touche d'origine	LOAD.L	A0,#R16"TAJUMP1	CALL	JUMPCAR	CALL	EXCADRE		; (SHOW-flche) ?	JUMP,EQ	LOOP3		; oui => LOOP3	COMP.W	D3,#F0+SHIFT	JUMP',LO 10$	COMP.W	D3,#F15+SHIFT	JUMP',HI 10$	SUB.B	D3,#SHIFT	; enlve (SHIFT) aux soft keys10$:	LIB	?MINMAJ		; D3 <-- touche majuscule	TEST.B	(A6)+OFLAGS:#BCOMM	JUMP',BC 30$	COMP.W	D3,#F1		; (F1) .. (F15) ?	JUMP',LO 30$		; non => 30$	COMP.W	D3,#F15	JUMP',HI 30$	LOAD.L	A2,#R16"TKMENC20$:	TEST.B	(A2)		; fin de la table ?	JUMP,EQ	ERRLIT		; oui => ERRLIT	COMP.B	D2,(A2+)	; touche trouve ?	JUMP,EQ	DOSTRING	; oui => DOSTRING25$:	TEST.B	(A2+)		; A2 <-- saute .ASCIZ	JUMP,NE	25$	JUMP	20$30$:	LOAD.L	A0,#R16"TAJUMP2	CALL	JUMPCAR	LOAD.L	A2,#R16"TXMM0	COMP.W	D2,#STAB	JUMP,EQ	DOSTRING	LOAD.L	A2,#R16"TXMM1	COMP.W	D2,#TAB	JUMP,EQ	DOSTRING	LOAD.L	A2,#R16"TXMM2	COMP.W	D2,#CTAB	JUMP,EQ	DOSTRING	COMP.W	D3,#H'80	JUMP,HS	ERRLIT	LOAD.B	D3,D2	JUMP	DOEDIT;;?	TEST.B	(A6)+OBUEXE	; premier caractre ?;;?	JUMP,EQ	DOEDIT		; oui => dite une ligne;;?	JUMP	DOINSERTTAJUMP1:	.W	KEYMPO,0,MOUSEP	.W	KEYMGP,KEYMMP,KEYMDP,0,MOUSEB	.W	KEYMGR,KEYMMR,KEYMDR,0,LOOP3	.W	0TAJUMP2:	.W	END,F0,0,DOEND	.W	SHIFT+END,PROGRA+END,0,DOARRET1	.W	CURSOR+'T,F1,0,DODEBUT	.W	CURSOR+'V,F2,0,DOFIN	.W	CURSOR+'E,0,DOEHAUT	.W	CURSOR+'X,0,DOEBAS	.W	CURSOR+'S,0,DOEGAUCHE	.W	CURSOR+'G,0,DOEDROITE	.W	CURSOR+'R,F4,F5,F6,0,DOHAUT	.W	CURSOR+'C,F7,F8,F9,0,DOBAS	.W	CURSOR+'D,F10,F11,F12,0,DOGAUCHE	.W	CURSOR+'F,F13,F14,F15,0,DODROITE	.W	UNDO,0,DOUNDO	.W	DEL,BS,0,DODEL	.W	DEFINE,0,DOSWAP	.W	MACRO,0,DOFLIP	.W	HELP,0,DOHELP	.W	ENTER,PROGRA+CR,0,DOIRETURN	.W	CR,0,DORETURN	.W	0DOEDIT:	CLR.L	(A6)+OPMENU	; signal soft-keys "dmolies"	LOAD.L	A3,#R16"TXMEED	LIB	?AFMENU		; met nouvelles soft-keys	LOAD.L	A5,#R16"TKMEED	; A5 <-- ^table d'insertions	CALL	INSERT		; insre le caractre frapp	CALL	KILMARK		; enlve toutes les marques	PUSH.B	(A6)+OBUEXE	CLR.B	(A6)+OBUEXE	CALL	AFCOMM		; affiche une commande vide !	POP.B	(A6)+OBUEXE	LOAD.L	A3,#(A6)+OBUEXE	; A3 <-- ^dbut ligne	LOAD.L	A4,A310$:	TEST.B	(A4+)	JUMP,NE	10$	DEC.L	A4		; A4 <-- ^fin ligne20$:	LOAD.L	D3,#ABUEXE	; D3 <-- lg max	LIB	?GETFILE	; attend ligne ...	COMP.W	D3,#SPACE	JUMP,EQ	20$	COMP.W	D3,#KEYMGP	JUMP,EQ	50$	COMP.W	D3,#KEYMMP	JUMP,EQ	50$	COMP.W	D3,#KEYMDP	JUMP,EQ	50$	COMP.W	D3,#END	JUMP,EQ	LOOP	COMP.W	D3,#F0	JUMP,EQ	LOOP	COMP.W	D3,#F0+SHIFT	JUMP,EQ	LOOP	LOAD.L	A0,#R16"TAJUMP2	CALL	JUMPCAR		; jump qq part				; touche invalide =>	LOAD.B	D3,#BIPLIT	LIB	?BEEP		; p'tit bruit	JUMP	20$50$:	CLR.B	(A6)+OBUEXE	; vide ligne de commande	LIB	?IFMOUSE	; D4 <-- position de la souris	JUMP,NE	LOOP1	CALL	DETECTE		; D4 <-- rang icone trouv	LOAD.W	(A6)+OLSTII,D4	JUMP	MOUSEBDOIRETURN:	TEST.B	(A6)+OFLAGS:#BLIST	JUMP',BS 60$	TEST.B	(A6)+OFLAGS:#BICONE	JUMP',BS 60$	TEST.B	(A6)+OBUEXE	JUMP',EQ 60$	COMP.B	(A6)+OBUEXE,#CR	; ligne de commande vide ?	JUMP,NE	EXECUTE		; non => EXECUTE60$:				; oui =>	LOAD.B	D3,#1		; D3 <-- excution immdiate	CALL	FRAPPE	JUMP	LOOP2DORETURN:	TEST.B	(A6)+OFLAGS:#BLIST	JUMP',BS 60$	TEST.B	(A6)+OFLAGS:#BICONE	JUMP',BS 60$	TEST.B	(A6)+OBUEXE	JUMP',EQ 60$	COMP.B	(A6)+OBUEXE,#CR	; ligne de commande vide ?	JUMP,NE	EXECUTE		; non => EXECUTE60$:				; oui =>	CLR.B	D3		; D3 <-- fait liste si ncessaire	CALL	FRAPPE	JUMP,NE	LOOP2EXECUTE:	CALL	KILMARK		; enlve les marques	LOAD.L	A4,#(A6)+OBUEXE	LOAD.L	A3,#R16"TACOMM10$:	LOAD.B	D3,(A3)		; fin de la table ?	JUMP,EQ	50$		; oui => 50$	COMP.B	D3,#'*	JUMP',EQ 13$	LOAD.B	D3,(A4)	LIB	?MINMAJ	LOAD.W	D7,#-1		; D7 <-- pas trouv	COMP.B	D3,(A3)		; premiers caractres identiques ?	JUMP',NE 15$		; non => 15$13$:	LOAD.L	A2,#R16"LSTTERM	; A2 <-- ^liste de terminateurs	LIB	?CPSTRING	; D7 <-- trouv oui/non15$:	TEST.B	(A3+)		; A3 <-- saute .ASCIZ	JUMP,NE	15$	LOAD.L	D3,A3	TEST.L	D3:#0	JUMP',BC 20$	INC.L	A3		; A3 <-- saute .EVEN20$:	ADD.L	A3,#2		; A3 <-- saute .W	TEST.W	D7	JUMP,NS	10$	CLR.L	D0	LOAD.W	D0,(A3)-2	; D0 <-- adresse relative	LOAD.L	A0,#R16"START	ADD.L	A0,D0		; A0 <-- adresse absolue	LOAD.L	A3,A4		; A3 <-- ^dbut commande	CLR.B	D3		; D3 <-- pas de switch30$:	TEST.B	(A3)	JUMP',EQ 40$	COMP.B	(A3),#CR	JUMP',EQ 40$	COMP.B	(A3),#SPACE	JUMP',EQ 40$	COMP.B	(A3+),#'/	JUMP,NE	30$	LOAD.B	D3,(A3)		; D3 <-- lettre aprs "/"	LIB	?MINMAJ		; D3 <-- lettre MAJUSCULE40$:	LOAD.L	A3,A4		; A3 <-- ^dbut commande	LIB	?SKPNAM		; A3 <-- ^premier argument	CALL	(A0)		; excute la commande ...	TEST.W	D7		; ok ?	JUMP',EQ 48$		; oui => 48$				; non =>	TEST.B	(A6)+OFLAGM:#BMACRO	JUMP',BC 45$	TEST.B	(A6)+OFLAGM:#BMSTOP	JUMP',BC 48$	CALL	ENDMACRO	; stoppe la macro45$:	TEST.W	(A6)+ONSWDO	; swdo existe ?	JUMP',NE 47$		; oui => 47$	PUSH.W	D7		; non =>	CALL	OPESWDO		; utilise la grande swdo	POP.W	D747$:	CALL	AFERR		; affiche l'erreur ...48$:	CALL	CLOSWDO		; ferme la grande sous-fentre	TEST.B	(A6)+OFLAGM:#BMACRO	JUMP,BS	LOOPM	JUMP	LOOP50$:	CLR.W	D4	LIB	?WAITMOUSE	; souris: met le sablier	LOAD.L	A3,#(A6)+OBUEXE	; A3 <-- ^ligne de commande	FOS	?EXECUTE	; excute dans une autre fentre	PUSH.W	D7	LOAD.W	D4,#1	LIB	?WAITMOUSE	; souris: remet la flche	POP.W	D7	JUMP',NE 60$	TEST.B	(A6)+OFLAGM:#BMACRO	JUMP,BS	LOOPM	JUMP	LOOP60$:	TEST.B	(A6)+OFLAGM:#BMACRO	JUMP',BC 62$	TEST.B	(A6)+OFLAGM:#BMSTOP	JUMP,BC	LOOPM62$:	PUSH.W	D7	CALL	OPESWDO		; ouvre la grande sous-fentre	POP.W	D7	CALL	AFERRP		; affiche l'erreur ...	CALL	CLOSWDO		; ferme la grande sous-fentre	JUMP	LOOPDOSWAP:	TNOT.B	(A6)+OFLAGS:#BCOMM	JUMP	LOOP1DOFLIP:	TNOT.B	(A6)+OFLAGS:#BAFMOD	JUMP	LOOPDOINSERT:	CALL	INSERT	JUMP,NE	ERRLIT	JUMP	LOOP2DOSTRING:	TEST.B	(A6)+OBUEXE	; buffer vide ?	JUMP',NE 20$		; non => 20$	COMP.B	(A2),#SPACE	; chane commence par SPACE ?	JUMP',NE 20$		; non => 20$	INC.L	A2		; oui => ne l'insre pas !20$:	LOAD.B	D3,(A2+)	JUMP',EQ 40$	CALL	INSERT		; insre un caractre	JUMP,NE	ERRLIT	JUMP	20$40$:	COMP.B	(A2)-2,#SPACE	; chane termne par <SPACE> ?	JUMP,NE	LOOP2		; non => LOOP2	LOAD.W	D3,#CARMARK	JUMP	DOEDIT		; oui => dite la ligneDODEL:	CALL	GETLAST		; D3 <-- dernier caractre frapp	COMP.B	D3,#CARMARK	; est-on sur une marque ?	JUMP,EQ	ERRLIT		; oui => ERRLIT	CALL	DETRUIT		; dtruit le dernier caractre	JUMP,NE	ERRLIT		; si buffer vide => ERRLIT	JUMP	LOOP2DOUNDO:	TEST.W	(A6)+OHISTL	; niveau zro ?	JUMP,EQ LOOP1		; oui => LOOP1	LOAD.W	(A6)+OHISTI,#-1	; non => retourne au niveau zro	JUMP	LOOPDOEND:	TEST.W	(A6)+OHISTL	; niveau zro ?	JUMP',EQ 40$		; oui => 40$	COMP.W	(A6)+OHISTL,#1	; premier niveau ?	JUMP,NE	LOOP		; non => retourne au premier niveau	LOAD.W	(A6)+OHISTI,#-1	; oui => retourne au niveau zro	JUMP	LOOP;;?	TEST.B	(A6)+OFLAGS:#BLIST;;?	JUMP,BS	LOOP		; liste de fichiers => LOOP;;?	TEST.B	(A6)+OFLAGS:#BICONE;;?	JUMP,BS	LOOP		; liste d'icones => LOOP40$:	LOAD.W	D4,#50/4	NTREL	?SETTIM	CALL	GETCAR		; 2me touche rapidement ?	PUSH.W	D7	LOAD.W	D4,#-1	NTREL	?SETTIM	POP.W	D7	JUMP,NE	ERRLIT		; non => ERRLIT	COMP.B	D3,#END	JUMP',EQ 50$	COMP.B	D3,#F0	JUMP',EQ 50$	COMP.B	D3,#F0+SHIFT	JUMP',EQ 50$	JUMP	ERRLIT50$:	CLR.W	D4	NTREL	?SETTIM	NTREL	?WFABDESC	; reste-t-il des fils ?	PUSH.W	D7	LOAD.W	D4,#-1	NTREL	?SETTIM	POP.W	D7	JUMP,NE	ERRLIT		; oui => ERRLIT	JUMP	QUITTE		; non => QUITTEDOHELP:	TCLR.B	(A6)+OFLAGS:#BAFMIN ; faudra refaire le cadre	LIB	?AFTIM	.B	EOP,NOCURS	.ASCII /Mode d'emploi rsum<CR>/	.ASCII /--------------------<CR>/	.B	CR	.ASCII /La touche (CURSOR) appuye simultanment avec les flches permet<CR>/	.ASCII /de dplacer le choix de l'icne comme suit :<CR>/	.ASCII /(CURSOR-F) -D)		avance ou recule horizontalement<CR>/	.ASCII /(CURSOR-R) -C)		monte ou descend<CR>/	.ASCII /(CURSOR-S) -G)		va au dbut ou  la fin de la ligne<CR>/	.ASCII /(CURSOR-E) -X)		va en haut ou en bas d'une colonne<CR>/	.ASCII /(CURSOR-T) -V)		va tout au dbut ou tout  la fin<CR>/	.B	CR	.ASCII /(RETURN)		excute l'icne choisie (pendant que la liste apparat,<CR>/	.ASCII /			une deuxime pression interrompt la liste et excute<CR>/	.ASCII /			immdiatement l'icne choisie)<CR>/	.ASCII /(PROGRA-RETURN)		idem, mais sans montrer la liste (le nom peut alors<CR>/	.ASCII /			tre tap en toutes lettres)<CR>/	.ASCII /(END) ou (Stop)		interrompt une action en cours<CR>/	.B	CR	.ASCII /Les noms peuvent aussi tre frappes manuellement :<CR>/	.ASCII /(<'<>--)			dtruit le dernier caractre frapp<CR>/	.ASCII /(UNDO)			dtruit tous les caractres frapps/	.B	0	.EVEN	CALL	GETCAR		; attend une touche ...	LOAD.B	D3,#EOP	LIB	?AFCAR		; efface toute la fentre	JUMP	LOOPDOHAUT:	LOAD.W	D4,(A6)+OLSTII	COMP.W	D4,#-1	JUMP',NE 10$	CLR.W	D410$:	TEST.B	(A6)+OFLAGS:#BLIST	JUMP,BS	50$		; liste => 50$				; icone =>	SUB.W	D4,(A6)+ONBICX	JUMP,LO	ERRLIT	JUMP	MICONE50$:	SUB.W	D4,(A6)+ONBFIX	JUMP,LO	ERRLIT	JUMP	MICONEDOBAS:	LOAD.W	D4,(A6)+OLSTII	COMP.W	D4,#-1	JUMP',NE 10$	CLR.W	D410$:	TEST.B	(A6)+OFLAGS:#BLIST	JUMP',BS 50$		; liste => 50$				; icone =>	ADD.W	D4,(A6)+ONBICX	COMP.W	D4,(A6)+ONBIC	JUMP,HS	ERRLIT	JUMP	MICONE50$:	ADD.W	D4,(A6)+ONBFIX	COMP.W	D4,(A6)+OSRCNN	JUMP,HS	ERRLIT	JUMP	MICONEDOGAUCHE:	LOAD.W	D4,(A6)+OLSTII	COMP.W	D4,#-1	JUMP',NE 10$	CLR.W	D410$:	DEC.W	D4	JUMP,LO	ERRLIT	JUMP	MICONEDODROITE:	LOAD.W	D4,(A6)+OLSTII	COMP.W	D4,#-1	JUMP',NE 10$	CLR.W	D410$:	TEST.B	(A6)+OFLAGS:#BLIST	JUMP',BS 50$		; liste => 50$				; icone =>	INC.W	D4	COMP.W	D4,(A6)+ONBIC	JUMP,HS	ERRLIT	JUMP	MICONE50$:	INC.W	D4	COMP.W	D4,(A6)+OSRCNN	JUMP,HS	ERRLIT	JUMP	MICONEDOEHAUT:	LOAD.W	D4,(A6)+OLSTII	COMP.W	D4,#-1	JUMP',NE 10$	CLR.W	D410$:	TEST.B	(A6)+OFLAGS:#BLIST	JUMP',BS 50$		; liste => 50$				; icone =>	AND.L	D4,#H'FFFF	DIV.WU	D4,(A6)+ONBICX	SWAP.W	D4	JUMP	MICONE50$:	AND.L	D4,#H'FFFF	DIV.WU	D4,(A6)+ONBFIX	SWAP.W	D4	JUMP	MICONEDOEBAS:	LOAD.W	D4,(A6)+OLSTII	COMP.W	D4,#-1	JUMP',NE 10$	CLR.W	D410$:	TEST.B	(A6)+OFLAGS:#BLIST	JUMP',BS 50$		; liste => 50$20$:				; icone =>	ADD.W	D4,(A6)+ONBICX	COMP.W	D4,(A6)+ONBIC	JUMP,LO	20$	SUB.W	D4,(A6)+ONBICX	JUMP	MICONE50$:	ADD.W	D4,(A6)+ONBFIX	COMP.W	D4,(A6)+OSRCNN	JUMP,LO	50$	SUB.W	D4,(A6)+ONBFIX	JUMP	MICONEDOEGAUCHE:	LOAD.W	D4,(A6)+OLSTII	COMP.W	D4,#-1	JUMP',NE 10$	CLR.W	D410$:	TEST.B	(A6)+OFLAGS:#BLIST	JUMP',BS 50$		; liste => 50$				; icone =>	AND.L	D4,#H'FFFF	DIV.WU	D4,(A6)+ONBICX	MUL.WU	D4,(A6)+ONBICX	JUMP	MICONE50$:	AND.L	D4,#H'FFFF	DIV.WU	D4,(A6)+ONBFIX	MUL.WU	D4,(A6)+ONBFIX	JUMP	MICONEDOEDROITE:	LOAD.W	D4,(A6)+OLSTII	COMP.W	D4,#-1	JUMP',NE 10$	CLR.W	D410$:	TEST.B	(A6)+OFLAGS:#BLIST	JUMP',BS 50$		; liste => 50$				; icone =>	AND.L	D4,#H'FFFF	DIV.WU	D4,(A6)+ONBICX	MUL.WU	D4,(A6)+ONBICX	ADD.W	D4,(A6)+ONBICX	DEC.W	D4	COMP.W	D4,(A6)+ONBIC	JUMP,LO	MICONE	LOAD.W	D4,(A6)+ONBIC	DEC.W	D4	JUMP	MICONE50$:	AND.L	D4,#H'FFFF	DIV.WU	D4,(A6)+ONBFIX	MUL.WU	D4,(A6)+ONBFIX	ADD.W	D4,(A6)+ONBFIX	DEC.W	D4	COMP.W	D4,(A6)+OSRCNN	JUMP,LO	MICONE	LOAD.W	D4,(A6)+OSRCNN	DEC.W	D4	JUMP	MICONEDODEBUT:	CLR.W	D4	JUMP	MICONEDOFIN:	TEST.B	(A6)+OFLAGS:#BLIST	JUMP',BS 50$		; liste => 50$				; icone =>	LOAD.W	D4,(A6)+ONBIC	DEC.W	D4	JUMP	MICONE50$:	LOAD.W	D4,(A6)+OSRCNN	DEC.W	D4	JUMP	MICONEMOUSEP:				; souris bouge =>	LIB	?IFMOUSE	; D4 <-- position de la souris	JUMP,NE	LOOP3	CALL	DETECTE		; D4 <-- rang icone trouvMICONE:	COMP.W	D4,(A6)+OLSTII	; autre icone ?	JUMP,EQ	LOOP3		; non => LOOP3				; oui =>	PUSH.L	D4	LOAD.W	D4,(A6)+OLSTII	; D4 <-- rang icone dessin	CALL	INVERSE		; efface icone/fichier actuel	POP.L	D4	CALL	INVERSE		; dessine nouvel icone/fichier	LOAD.W	(A6)+OLSTII,D4	JUMP	LOOP3MOUSEB:				; bouton souris press =>	CLR.B	D3		; D3 <-- fait liste si ncessaire	CALL	FRAPPE	JUMP,NE	LOOP2	TEST.B	(A6)+OFLAGK:#BKEYMP ; bouton souris press ?	JUMP,BC	EXECUTE		; non => EXECUTE20$:				; oui => attend qu'il soit relach	LIB	?GETCAR		; attend clavier/souris ...	CALL	FILTRE		; filtre touche souris	COMP.W	D3,#KEYMGR	; bouton souris relach ?	JUMP,EQ	EXECUTE		; oui => EXECUTE	COMP.W	D3,#END	JUMP,EQ	LOOP	COMP.W	D3,#F0	JUMP,EQ	LOOP	COMP.W	D3,#F0+SHIFT	JUMP,EQ	LOOP	JUMP	20$ERRLIT:				; touche incorrecte =>	LOAD.B	D3,#BIPLIT	LIB	?BEEP		; p'tit bruit	JUMP	LOOP3	.END